components.css:
.ds-btn-primary {
  font-family: JetBrains Mono, IBM Plex Mono, ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, "Liberation Mono", "Courier New", monospace;
  font-size: 16px;
  font-weight: 500;
  line-height: 1.5;
  color: var(--canvas);
  background-color: var(--ink);
  border: 1px solid var(--ink);
  border-radius: 4px;
  padding: 4px 20px;
  cursor: pointer;
  transition: background-color 150ms cubic-bezier(0.4, 0, 0.2, 1), border-color 150ms cubic-bezier(0.4, 0, 0.2, 1);
}
.ds-btn-primary:hover {
  background-color: var(--ink-deep);
  border-color: var(--ink-deep);
}
.ds-btn-primary:focus-visible {
  outline: 2px solid var(--ink);
  outline-offset: 2px;
}

.ds-btn-secondary {
  font-family: JetBrains Mono, IBM Plex Mono, ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, "Liberation Mono", "Courier New", monospace;
  font-size: 16px;
  font-weight: 500;
  line-height: 1.5;
  color: var(--ink);
  background-color: var(--canvas);
  border: 1px solid var(--hairline-strong);
  border-radius: 4px;
  padding: 4px 20px;
  cursor: pointer;
  transition: background-color 150ms cubic-bezier(0.4, 0, 0.2, 1), border-color 150ms cubic-bezier(0.4, 0, 0.2, 1);
}
.ds-btn-secondary:hover {
  background-color: var(--surface-soft);
}
.ds-btn-secondary:focus-visible {
  outline: 2px solid var(--ink);
  outline-offset: 2px;
}

.ds-chip {
  font-family: JetBrains Mono, IBM Plex Mono, ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, "Liberation Mono", "Courier New", monospace;
  font-size: 16px;
  font-weight: 500;
  line-height: 1.5;
  color: var(--ink);
  background-color: var(--surface-card);
  border: 1px solid var(--hairline);
  border-radius: 4px;
  padding: 4px 16px;
  cursor: pointer;
  transition: background-color 150ms cubic-bezier(0.4, 0, 0.2, 1), border-color 150ms cubic-bezier(0.4, 0, 0.2, 1), color 150ms cubic-bezier(0.4, 0, 0.2, 1);
}
.ds-chip:hover {
  background-color: var(--surface-soft);
}
.ds-chip-selected {
  color: var(--canvas);
  background-color: var(--ink);
  border-color: var(--ink);
}
.ds-chip-selected:hover {
  background-color: var(--ink-deep);
  border-color: var(--ink-deep);
}
.ds-chip:focus-visible {
  outline: 2px solid var(--ink);
  outline-offset: 2px;
}

.ds-output-card {
  font-family: JetBrains Mono, IBM Plex Mono, ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, "Liberation Mono", "Courier New", monospace;
  color: var(--on-dark);
  background-color: var(--surface-dark);
  border-radius: 0;
  padding: 32px;
}
.ds-output-pill {
  display: inline-block;
  font-size: 14px;
  color: var(--ash);
  background-color: var(--surface-dark-elevated);
  border-radius: 4px;
  padding: 8px 12px;
  margin-bottom: 24px;
}
.ds-output-quote {
  font-size: 24px;
  font-weight: 500;
  line-height: 1.5;
  margin: 0 0 24px;
}
.ds-output-badge {
  display: inline-block;
  font-size: 14px;
  font-weight: 500;
  color: var(--on-dark);
  background-color: var(--surface-dark-elevated);
  border-radius: 4px;
  padding: 2px 8px;
}

.ds-select {
  font-family: JetBrains Mono, IBM Plex Mono, ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, "Liberation Mono", "Courier New", monospace;
  font-size: 14px;
  font-weight: 500;
  line-height: 1.5;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  color: var(--ink);
  background-color: var(--surface-card);
  border: 1px solid var(--hairline);
  border-radius: 4px;
  padding: 4px 12px;
  cursor: pointer;
}
.ds-select:focus-visible {
  outline: 2px solid var(--ink);
  outline-offset: 2px;
}

.ds-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 16px;
  padding-bottom: 16px;
  border-bottom: 1px solid var(--hairline);
}
.ds-wordmark {
  font-family: JetBrains Mono, IBM Plex Mono, ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, "Liberation Mono", "Courier New", monospace;
  font-size: 16px;
  font-weight: 700;
  letter-spacing: -0.025em;
  color: var(--ink);
}
.ds-header-controls {
  display: flex;
  align-items: center;
  gap: 8px;
}
.ds-btn-ghost {
  font-family: JetBrains Mono, IBM Plex Mono, ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, "Liberation Mono", "Courier New", monospace;
  font-size: 16px;
  font-weight: 500;
  color: var(--ink);
  background: transparent;
  border: none;
  border-radius: 4px;
  padding: 4px 8px;
  cursor: pointer;
}
.ds-btn-ghost:focus-visible {
  outline: 2px solid var(--ink);
  outline-offset: 2px;
}

.ds-error {
  font-family: JetBrains Mono, IBM Plex Mono, ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, "Liberation Mono", "Courier New", monospace;
  font-size: 16px;
  line-height: 1.5;
  color: #ff3b30;
}
